Here's how to use MSTest's comparison assertions for your `ScoreCalculator`:

## Comparison Assertions (MSTest 3.x+)

```csharp
Assert.IsGreaterThan(lowerBound, actual);   // actual > lowerBound
Assert.IsLessThan(upperBound, actual);      // actual < upperBound
Assert.IsInRange(actual, low, high);        // low <= actual <= high
```

## Test Class for Your ScoreCalculator

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(3, 7);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);   // result > 0
        Assert.IsLessThan(100.0, result);    // result < 100
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(5, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    [TestMethod]
    [DataRow(95.0, "A")]
    [DataRow(90.0, "A")]
    [DataRow(85.0, "B")]
    [DataRow(80.0, "B")]
    [DataRow(75.0, "C")]
    [DataRow(70.0, "C")]
    [DataRow(65.0, "D")]
    [DataRow(60.0, "D")]
    [DataRow(55.0, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(double percentage, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(percentage));
    }

    [TestMethod]
    [DataRow(50.0, 100.0, 50.0)]
    [DataRow(100.0, 100.0, 100.0)]
    [DataRow(0.0, 50.0, 0.0)]
    public void NormalizeScore_ValidInputs_ReturnsExpected(double raw, double max, double expected)
    {
        Assert.AreEqual(expected, _calculator.NormalizeScore(raw, max));
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(150.0, 100.0);

        Assert.AreEqual(100.0, result);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_PartialScore_IsInRange()
    {
        var result = _calculator.NormalizeScore(30.0, 80.0);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }
}
```

## Key Takeaways

| Assertion | Meaning |
|-----------|---------|
| `Assert.IsGreaterThan(0.0, result)` | result > 0.0 |
| `Assert.IsLessThan(100.0, result)` | result < 100.0 |
| `Assert.IsInRange(result, 0.0, 100.0)` | 0.0 ≤ result ≤ 100.0 |

These give much better failure messages than `Assert.IsTrue(result > 0)` — on failure they'll show the actual value vs. the bound, not just "expected True, got False".
